Here is a simple C++ function that uses the `std::regex` library to replace Markdown syntax with HTML:

```cpp
#include <regex>
#include <string>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;

    // Headers
    html += "<h1>" + std::regex_replace(markdown, std::regex("^# (.*)"), "$1</h1>") + "</h1>";

    // Bold and Italic
    html += std::regex_replace(markdown, std::regex("(\*([^\*]+)\*)|(_([^\_]+)_)", std::regex_constants::ECMAScript), 
        std::regex::format("<$2>$3</$2>") + std::regex::format("<i>$3</i>"));

    // Links
    html += std::regex_replace(markdown, std::regex("(\[(.+?)\]\((.+?)\))", std::regex_constants::ECMAScript), 
        "<a href=\"$2\">$1</a>");

    // Lists
    html += std::regex_replace(markdown, std::regex("^([ \t]*)# (.*)$", std::regex_constants::ECMAScript), 
        "$1<ul><li>$2</li></ul>");

    // Code blocks
    html += std::regex_replace(markdown, std::regex("```(.*)```", std::regex_constants::ECMAScript), 
        "<pre><code>$1</code></pre>");

    return html;
}
```

This function is quite basic and doesn't support all Markdown syntax, but it should give you a good starting point. You can add more replacements as needed.

